  "main.rs": "use itertools::Itertools;

/// Tokenizes a shell command string in a quote-aware fashion.
/// Single quotes preserve the literal value of all characters within them.
/// Whitespace outside quotes separates tokens, but whitespace inside quotes is preserved.
fn tokenize(s: &str) -> Vec<String> {
    s.split("'")
        .enumerate()
        .map(|(i, part)| {
            if i % 2 == 0 {
                // Outside quotes: split into space and non-space groups
                part.chars()
                    .group_by(|&c| *c == ' ')
                    .into_iter()
                    .map(|(is_space, group)| (is_space, group.collect::<String>()))
                    .collect::<Vec<_>>()
            } else {
                // Inside quotes: treat as a single non-space token
                vec![(false, part.to_string())]
            }
        })
        .flatten()
        // Group consecutive non-space segments together (they form one token)
        .group_by(|(is_space, _)| !*is_space)
        .into_iter()
        .filter_map(|(is_token, group)| {
            if is_token {
                // Concatenate all non-space segments in this token
                Some(group.map(|(_, s)| s).join(""))
            } else {
                // Skip whitespace-only groups
                None
            }
        })
        .collect()
}

